Why SaveTasks method don't save in .json? using System.Collections.Generic;
using System.IO;
using UnityEngine;

public static class DataBase
{
    private const string filePath = "tasks.json";

    private static List<Task> tasks;

    static DataBase()
    {
        tasks = LoadTasks();

    }

    private static List<Task> LoadTasks()
    {
        List<Task> taskList = new List<Task>();

        if (File.Exists(filePath))
        {
            string json = File.ReadAllText(filePath);
            if (!string.IsNullOrEmpty(json))
            {
                taskList = JsonUtility.FromJson<List<Task>>(json);
            }
        }
        else
        {
            SaveTasks();
        }

        return taskList;
    }

    private static void SaveTasks()
    {
        string json = JsonUtility.ToJson(tasks);
        File.WriteAllText(filePath, json);

    }

    public static void AddTask(Task task)
    {
        tasks.Add(task);
        SaveTasks();
    }

    public static void RemoveTask(Task task)
    {
        tasks.Remove(task);
        SaveTasks();
    }

    public static List<Task> GetTasks()
    {
        return tasks;
    }
}

The `SaveTasks` method is not saving the tasks to a file because the `tasks` variable being passed to the `JsonUtility.ToJson` method is a `List<Task>` and not a `Task[]`.

In the `SaveTasks` method, you are trying to convert a `List<Task>` to a `string` by calling `JsonUtility.ToJson(tasks)`, but `JsonUtility.ToJson` expects an array of objects to convert to json, not a list.

Also, you are trying to call the `SaveTasks` method inside the `AddTask` and `RemoveTask` methods, but it should be called outside of these methods, ideally in the `static` constructor or in a separate method.

You can fix this issue by changing the `SaveTasks` method to accept a `Task[]` instead of a `List<Task>`, and by calling `JsonUtility.ToJson` on the `tasks` array instead of the `tasks` list.

You should also move the `SaveTasks` method call to the `static` constructor or in a separate method so that it is only called once when the tasks are first created.

Here is an example of how the `SaveTasks` method could be rewritten:
```
private static Task[] tasksArray;

static DataBase()
{
    tasksArray = LoadTasks();
}

private static Task[] LoadTasks()
{
    Task[] taskArray = new Task[tasks.Count];

    tasks.CopyTo(taskArray);

    return taskArray;
}

private static void SaveTasks()
{
    string json = JsonUtility.ToJson(tasksArray);
    File.WriteAllText(filePath, json);
}
```
And also you should change the `AddTask` and `RemoveTask` methods, so that they add and remove elements from the `tasksArray` instead of the `tasks` list.
```
public static void AddTask(Task task)
{
    taskArray[tasks.Count] = task;
    SaveTasks();
}

public static void RemoveTask(Task task)
{
    taskArray[tasks.IndexOf(task)] = null;
    SaveTasks();
}
```
